def f(x):
    return x**2

def riemann_sum(f, a, b, n, method='left'):
    """Approximate area under f from a to b using n rectangles."""
    width = (b - a) / n
    total = 0
    for i in range(n):
        if method == 'left':
            x_i = a + i * width
        elif method == 'right':
            x_i = a + (i + 1) * width
        elif method == 'mid':
            x_i = a + (i + 0.5) * width
        total += f(x_i) * width
    return total

# Compare accuracy as n increases
for n in [6, 100, 10000, 100000]:
    approx = riemann_sum(f, 1, 4, n, 'left')
    print(f"n={n:7d}: {approx:.6f}")
print(f"Exact:         21.000000")
